mapper.select:
SELECT
    id,
    course_id        AS courseId,
    chapter_id       AS chapterId,
    user_id          AS userId,
    parent_id        AS parentId,
    content,
    like_count       AS likeCount,
    reply_count      AS replyCount,
    is_teacher_reply AS isTeacherReply,
    status,
    created_time     AS createdTime,
    updated_time     AS updatedTime
FROM course_discussion


        AND course_id = #{q.courseId}


        AND chapter_id = #{q.chapterId}


        AND user_id = #{q.userId}


        AND parent_id = #{q.parentId}


        AND is_teacher_reply = #{q.isTeacherReply}


        AND status = #{q.status}


        AND created_time BETWEEN #{q.beginTime} AND #{q.endTime}


ORDER BY created_time DESC

